import React, { useContext, useEffect, useState } from 'react';

import { UserContext } from '@providers/User';
import SubscriptionStatusCard from '@components/userControlPanel/UserForm/AdminMenu/SubscriptionStatusCard';

import * as styles from './planExpiryGateway.module.css';

export default function PlanExpiryGateway({ children }) {
	const { exp: usrPlanExpiry, isPlanActive: chkIfPlanActive } = useContext(UserContext);
	const [isPlanActive, setIsPlanActive] = useState(async () => {
		if (!chkIfPlanActive || typeof chkIfPlanActive !== 'function') return false;
		return await chkIfPlanActive();
	}); // useState(false);

	useEffect(() => {
		// console.log('usrPlanExpiry:', usrPlanExpiry);
		// console.log('isPlanActive:', isPlanActive);
		if (!chkIfPlanActive || typeof chkIfPlanActive !== 'function') return;
		(async () => {
			const isActive = await chkIfPlanActive();
			// console.log('isActive', isActive);
			setIsPlanActive(isActive);
		})();
	}, [usrPlanExpiry]);
	return <div className={styles.paidAreaContentC}>{isPlanActive ? children : <SubscriptionStatusCard />}</div>;
}
