import React from 'react';
import { Link } from 'gatsby';
// import UserDropDown from '@components/userControlPanel/UserDropdown';
import Header from '@components/Header';
// import { LinkButton } from '@ui/Button';
// import KaagziLogo from '@img/logo.svg';
// import KiteLogo from '@img/logo-kite.png';
// import AngelOneLogo from '@img/logo-angelOne.webp';

import * as styles from './brokerLogin.module.css';

/**
 * Displays login page for broker
 * @param {Object} prop Prop passed to this component
 * @param {('Zerodha'| 'Angel One'| 'Upstox'| 'Alice Blue')} prop.broker Stock Broker
 * @param {?()=>{}} [prop.doOnLoginClick] Callback fn to execute once user clicks the login btn
 * @param {?string} [prop.goToUrlOnLoginClick] Go to broker login page once user clicks the login btn. Ignored if 'doOnLoginClick' callback fn is provided
 */
export default function BrokerLogin({ broker, doOnLoginClick, goToUrlOnLoginClick }) {
	if (!['Zerodha', 'Angel One', 'Upstox', 'Alice Blue'].includes(broker)) return null;
	return (
		<>
			{/* <header className={styles.brokerLoginHdr}>
				<img src="/img/logo.svg" alt="Kaagzi" />
				<UserDropDown />
			</header> */}
			<Header />
			<div id={styles.noUserWrap}>
				<div>
					{doOnLoginClick && typeof doOnLoginClick === 'function' ? (
						<button className={styles.brokerLoginCta} onClick={doOnLoginClick}>
							{broker === 'Zerodha' && <img src="/img/logo-kite.png" alt="Zerodha Kite" />}
							{broker === 'Angel One' && <img src="/img/logo-angelOne.webp" alt="Angel One" />}
							<span>Sign into {broker}</span>
						</button>
					) : (
						<a className={styles.brokerLoginCta} href={goToUrlOnLoginClick} target="_blank" rel="noopener noreferrer">
							{broker === 'Zerodha' && <img src="/img/logo-kite.png" alt="Zerodha Kite" />}
							{broker === 'Angel One' && <img src="/img/logo-angelOne.webp" alt="Angel One" />}
							<span>Sign into {broker}</span>
						</a>
					)}
					{/* <p>
						Don&apos;t have an account with {broker}? <a href="#">Open Account</a>
					</p> */}
					<div className={styles.orSep}>OR</div>
					<Link className={styles.brokerSwitchBtn} to="/app">
						{/* Choose another broker */}
						Choose different broker
					</Link>
				</div>
			</div>
		</>
	);
}
