		mcxQuotesBasket = useRef(/** @type {Object.<number, {ltp:number,cp:number }>}*/ ({}));

	const isOnline = useContext(NetworkCheckContext);
	const { id: angelOneUserId, feedToken } = useContext(AngelOneUserContext);

	/** @type {{current:?WebSocket}} */
	const webSocketRef = useRef(null);
	const heartbeatIntervalRef = useRef(null);

	// /** Instruments already subscribed to
